function videoBytes(): Uint8Array {
	const bin = atob(VIDEO_B64);
	const bytes = new Uint8Array(bin.length);
	for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
	return bytes;
}

interface VideoLike {
	src: string;
	muted: boolean;
	loop: boolean;
	paused: boolean;
	ended: boolean;
	seeking: boolean;
	duration: number;
	currentTime: number;
	videoWidth: number;
	videoHeight: number;
	readyState: number;
	play(): Promise<void>;
	pause(): void;
	getVideoPlaybackQuality(): VideoPlaybackQuality;
	addEventListener(type: string, cb: (ev: any) => void, opts?: any): void;
}

function createVideo(): VideoLike {
	if (typeof (globalThis as any).Video !== 'undefined') {
		return new (globalThis as any).Video();
	}
	return document.createElement('video') as unknown as VideoLike;
}

function waitEvent(
	target: VideoLike,
	type: string,
	timeoutMs = 15000,
): Promise<boolean> {
	return new Promise((resolve) => {
		const timo = setTimeout(() => resolve(false), timeoutMs);
		target.addEventListener(
			type,
			() => {
				clearTimeout(timo);
				resolve(true);
			},
			{ once: true },
		);
	});
}

function sleep(ms: number): Promise<void> {
	return new Promise((r) => setTimeout(r, ms));
}

// Draw the current frame and return the RGBA of the center pixel.
function centerPixel(video: VideoLike): [number, number, number, number] {
	const canvas = new OffscreenCanvas(320, 180);
	const ctx = canvas.getContext('2d')!;
	ctx.drawImage(video as any, 0, 0);
	const d = ctx.getImageData(160, 90, 1, 1).data;
	return [d[0], d[1], d[2], d[3]];
}

function isColor(
	px: [number, number, number, number],
	r: number,
	g: number,
	b: number,
): boolean {
	const tol = 24; // YUV 4:2:0 roundtrip tolerance
	return (
		Math.abs(px[0] - r) <= tol &&
		Math.abs(px[1] - g) <= tol &&
		Math.abs(px[2] - b) <= tol &&
		px[3] === 255
	);
}

function loadVideo(): { video: VideoLike; loaded: Promise<boolean> } {
	const video = createVideo();
	video.muted = true;
	const loaded = waitEvent(video, 'loadedmetadata');
	video.src = URL.createObjectURL(
		new Blob([videoBytes()], { type: 'video/webm' }),
	);
	return { video, loaded };
}

test('video metadata', async (t) => {
	const { video, loaded } = loadVideo();
	t.ok(await loaded, 'loadedmetadata fired');
	t.equal(video.videoWidth, 320, 'videoWidth');
	t.equal(video.videoHeight, 180, 'videoHeight');
	t.ok(Math.abs(video.duration - 2) < 0.2, 'duration is ~2s');
	t.equal(video.paused, true, 'starts paused');
	t.equal(video.ended, false, 'not ended');
	t.equal(video.currentTime, 0, 'currentTime starts at 0');
});

test('video seek + frame pixels', async (t) => {
	const { video, loaded } = loadVideo();
	t.ok(await loaded, 'loadedmetadata fired');

	// Seek (while paused) into the red half, then the blue half.
	const seeked1 = waitEvent(video, 'seeked');
	video.currentTime = 0.5;
	t.ok(await seeked1, 'seeked event fired');
	t.ok(Math.abs(video.currentTime - 0.5) < 0.1, 'currentTime after seek');
	await sleep(100); // let the frame present
	t.ok(isColor(centerPixel(video), 255, 0, 0), 'frame at 0.5s is red');

	const seeked2 = waitEvent(video, 'seeked');
	video.currentTime = 1.5;
	t.ok(await seeked2, 'second seeked event fired');
	await sleep(100);
	t.ok(isColor(centerPixel(video), 0, 0, 255), 'frame at 1.5s is blue');
});

test('video playback', async (t) => {
	const { video, loaded } = loadVideo();
	t.ok(await loaded, 'loadedmetadata fired');

	const played = waitEvent(video, 'play');
	await video.play();
	t.ok(await played, 'play event fired');
	t.equal(video.paused, false, 'not paused while playing');

	await sleep(700);
	t.ok(video.currentTime > 0.3, 'currentTime advances during playback');

	video.pause();
	t.equal(video.paused, true, 'paused after pause()');
	const frozen = video.currentTime;
	await sleep(300);
	t.ok(
		Math.abs(video.currentTime - frozen) < 0.05,
		'currentTime frozen while paused',
	);

	const q = video.getVideoPlaybackQuality();
	t.ok(q.totalVideoFrames > 5, 'frames were presented');
});

test('video ended event', async (t) => {
	const { video, loaded } = loadVideo();
	t.ok(await loaded, 'loadedmetadata fired');
	const seeked = waitEvent(video, 'seeked');
	video.currentTime = 1.7;
	await seeked;
	const ended = waitEvent(video, 'ended', 10000);
	await video.play();
	t.ok(await ended, 'ended event fired');
	t.equal(video.ended, true, 'ended is true');
	t.equal(video.paused, true, 'paused after ended');
	t.ok(Math.abs(video.currentTime - 2) < 0.2, 'currentTime at duration');
});

test('video looping', async (t) => {
	const { video, loaded } = loadVideo();
	t.ok(await loaded, 'loadedmetadata fired');
	video.loop = true;
	t.equal(video.loop, true, 'loop property set');
	const seeked = waitEvent(video, 'seeked');
	video.currentTime = 1.7;
	await seeked;
	let sawEnded = false;
	video.addEventListener('ended', () => {
		sawEnded = true;
	});
	await video.play();
	await sleep(1500);
	t.equal(sawEnded, false, 'no ended event while looping');
	t.equal(video.ended, false, 'ended stays false while looping');
	t.ok(video.currentTime < 1.5, 'currentTime wrapped around');
	video.pause();
});
